VALUES
  ('akshare_a_spot', 'A股实时行情', '腾讯财经（主）/ AKShare（备）', 'akshare', 'market', '采集全市场个股价格、涨跌幅、成交额，用于市场宽度、情绪、热度和个股基础行情。', 1, '交易日 17:20 Asia/Shanghai', '["market_prices","market_breadth"]', 28, '{"script":"scripts/collect_market_data.py","primary":"tencent_getBoardRankList","endpoint":"https://proxy.finance.qq.com/cgi/cgi-bin/rank/hs/getBoardRankList","pageSize":200,"fallbacks":["eastmoney_direct_clist","stock_zh_a_spot_em","stock_zh_a_spot_sina"],"maxRows":400,"retries":3}', 'GitHub Actions Python ETL', '腾讯接口负责全市场宽度，D1 只落前 400 行个股行情；每次运行会记录实际命中的 provider。'),
  ('akshare_boards', '行业与概念板块', 'AKShare', 'akshare', 'market', '采集行业和概念板块强弱、扩散、热度，用于自动识别结构分子、短期故事和四象限候选。', 1, '交易日 17:20 Asia/Shanghai', '["themes","narrative_events","quadrant_items"]', 28, '{"script":"scripts/collect_market_data.py","package":"akshare","primary":"eastmoney_direct_board_clist","functions":["stock_board_industry_name_em","stock_board_concept_name_em"],"fallbacks":["stock_board_industry_name_em","stock_board_concept_name_em"],"maxThemes":12}', 'GitHub Actions Python ETL', '该数据只用于板块强弱和主题识别；产业订单/产能仍需要事件证据或人工确认补强。'),
  ('akshare_macro', '宏观慢变量自动采集', 'AKShare', 'akshare', 'macro', '尝试采集 PMI、CPI、PPI、社融等慢变量，用于自动派生总量分子。', 1, '交易日 17:20 Asia/Shanghai', '["macro_observations"]', 720, '{"script":"scripts/collect_market_data.py","package":"akshare","functions":["macro_china_pmi_yearly","macro_china_cpi_yearly","macro_china_ppi_yearly","macro_china_shrzgm"]}', 'GitHub Actions Python ETL', '如果宏观接口不可用，系统不会编造方向，而是以中性低置信度处理总量分子。'),
  ('yfinance_anchors', '港美与商品锚', 'yfinance', 'yfinance', 'anchor', '采集港股、美股、商品、汇率等外部锚，支持中期基线确认。', 1, '交易日 17:20 Asia/Shanghai', '["anchor_assets"]', 36, '{"script":"scripts/collect_market_data.py","package":"yfinance","function":"yf.download","tickers":["HG=F","ALI=F","GC=F","CL=F","DX-Y.NYB","^TNX","USDCNY=X"],"period":"1mo"}', 'GitHub Actions Python ETL', 'yfinance 用于个人研究用途，部署前应确认数据使用边界。'),
  ('manual_macro', '宏观慢变量', 'Manual', 'manual', 'macro', '人工补充或覆盖 PMI、CPI/PPI、工业企业利润、社融、指数盈利等低频变量。', 1, '数据发布日人工录入', '["macro_observations","factor_states"]', 720, '{"approvalRequired":true}', '人工确认', '自动宏观采集失败或数据口径不合适时，用该入口人工补强证据。'),
  ('manual_narratives', '结构叙事与产业事件', 'Manual', 'manual', 'narrative', '人工补充结构主题、产业事件、主题资产映射和人工确认。', 1, '盘后复盘时录入', '["themes","theme_assets","narrative_events","factor_states","baseline_states","quadrant_items"]', 72, '{"approvalRequired":true,"supportsOverrides":true}', '人工确认', '短期故事必须记录与中期基线的连接证据。'),
  ('github_actions_etl', '收盘后采集任务', 'GitHub Actions', 'github_actions', 'orchestration', '在收盘后运行 Python ETL，生成 SQL 并写入 Cloudflare D1。', 1, '20 9 * * 1-5 UTC', '["data_collection_runs","market_prices","market_breadth","anchor_assets","macro_observations"]', 28, '{"workflow":".github/workflows/collect-market-data.yml","script":"scripts/collect_market_data.py","writesRunLog":true}', 'GitHub Actions', 'Cloudflare Worker 不跑 Python，只负责 API、配置和状态查看。'),
  ('model_derivation', '模型状态自动派生', 'Python ETL', 'github_actions', 'orchestration', '根据原始行情、板块、宏观和锚资产数据自动生成三因子、基线和四象限候选。', 1, '跟随收盘后采集任务', '["factor_states","baseline_states","themes","narrative_events","quadrant_items"]', 28, '{"script":"scripts/collect_market_data.py","stage":"derive_model_state","inputs":["market_breadth","anchor_assets","macro_observations","AKShare board snapshots"]}', 'GitHub Actions Python ETL', '派生结果带证据链；微观订单/产能缺失时降低置信度或提示人工补强。'),
  ('cloudflare_health', 'Cloudflare 健康检查', 'Cloudflare Workers', 'cloudflare_worker', 'orchestration', '提供 /api/health 和轻量状态检查，后续可扩展为定时重算状态。', 1, '按需请求', '["data_sources","data_collection_runs"]', 24, '{"endpoint":"/api/health"}', 'Cloudflare Pages Functions', '不承担 AKShare/yfinance 采集。');
